// NODO: HoneyPot_Asset_Updater (UPDATED: Custom Domain Path)
const input = $input.first().json;

// 1. Prepariamo l'oggetto HoneyPot
let honeyPot = input.HoneyPot || {};
if (!honeyPot.assets) honeyPot.assets = {};

// 2. Dati Input
const vatNumber = input.owner_data.vat_number;
const assetType = input.user_request.asset_type; // es. "logo" o "photo"
const mimeType = input.user_request.mime_type || "image/jpeg";
let ext = mimeType.split('/')[1] || "jpg";
if (ext === "jpeg") ext = "jpg"; // Standardizziamo jpeg in jpg se preferisci

// 3. Dati AI
let analysisNode = input.Asset || input.output || {};
let analysis = analysisNode.Asset || analysisNode;
if (typeof analysis === 'string') { try { analysis = JSON.parse(analysis); } catch(e){} }

// 4. GENERAZIONE URL PERSONALIZZATO
// Struttura desiderata: https://dashboard.trinai.it/[vat_number]/[asset_type].[ext]
const domain = "https://dashboard.trinai.it";
const finalUrl = `${domain}/${vatNumber}/${assetType}.${ext}`;

// 5. Definizione percorso per GitHub (se carichi ancora su GitHub)
// Se il server punta alla repo, il file deve essere salvato come "vat_number/asset_type.ext"
const ghPath = `${vatNumber}/${assetType}.${ext}`;

// 6. Costruzione Oggetto Asset
const assetObj = {
    url: finalUrl, 
    mime: mimeType,
    description: analysis.display_text || "Analisi completata",
    meta: {
        visual_analysis: analysis.visual_analysis,
        pro_tip: analysis.pro_tip,
        colors: analysis.dominant_colors || []
    },
    updated_at: new Date().toISOString()
};

// 7. Aggiornamento in memoria
honeyPot.assets[assetType] = assetObj;

// 8. Output
return {
    json: {
        HoneyPot: honeyPot, 
        owner_data: input.owner_data,
        FirstAsset: input.FirstAsset,
        // Payload per l'upload (usiamo ghPath per mantenere la struttura cartelle)
        gh_upload: {
            fileName: ghPath, 
            content: input.user_request.file_data
        },

        response_data: {
            url: finalUrl,
            description: assetObj.description
        }
    }
};

// NODO: Validate_Bot_Token_API
// OBIETTIVO: Validare il token ricevuto dalla MiniApp

const input = $input.first().json;
const botToken = input.user_request.bot_token;
const vatNumber = input.user_request.vat_number;

if (!botToken) {
    return { json: { error: "Token mancante" } };
}

// Regex Validazione (ID:SECRET)
const tokenRegex = /^(\d{6,10}):([A-Za-z0-9_-]{30,})$/;
const isValid = tokenRegex.test(botToken);

if (!isValid) {
    return { json: { error: "Formato token non valido", valid: false } };
}

return {
    json: {
        valid: true,
        bot_token: botToken,
        vat_number: vatNumber,
    }
};

