const input = $input.all()[0].json;

// Prendi il fragment aggiornato da TimeCange
const updatedContactHours = input.TimeCange;

// Clona HoneyPot completo
const updatedHoneyPot = JSON.parse(JSON.stringify(input.user_request.honeypot_update));

// Trova l'indice del fragment CONTACT_HOURS_V1
const fragmentIndex = updatedHoneyPot.knowledge_fragments.findIndex(
  f => f.fragment_id === 'CONTACT_HOURS_V1'
);

// Sostituisci o aggiungi il fragment aggiornato
if (fragmentIndex !== -1) {
  updatedHoneyPot.knowledge_fragments[fragmentIndex] = updatedContactHours;
} else {
  updatedHoneyPot.knowledge_fragments.push(updatedContactHours);
}

// Restituisci tutto il JSON con HoneyPot aggiornato
return {
  json: {
    ...input,
    HoneyPot: updatedHoneyPot
  }
};

